#include<bits/stdc++.h>
using namespace std;
long long n;
long long k[500010],a[500010];
long long tr[2][500010],ans[500010];
pair<long long,long long> p[500010];
vector<long long> v[500010];
long long lowbit(long long x)
{
    return x&-x;
}
void update(long long x,long long v,long long id)
{
    for(long long i=x;i<=n;i+=lowbit(i))
    {
        tr[id][i]+=v;
    }
}
long long query(long long x,long long id)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=tr[id][i];
    }
    return ans;
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&p[i].first);
        p[i].second=i;
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&k[i]);
    }
    sort(p+1,p+1+n);
    for(long long i=1;i<=n;i++)
    {
        a[i]=p[i].first;
    }
    for(long long i=1;i<=n;i++)
    {
        long long l=lower_bound(a+1,a+1+i,a[i]-k[p[i].second])-a;
        long long r=upper_bound(a+i,a+1+n,a[i]+k[p[i].second])-a-1;
        ans[p[i].second]+=query(i,0)-query(l-1,0);
        update(i,1,0);
        update(l,1,1);
        update(i+1,-1,1);
        v[r].push_back(i);
        for(long long j:v[i])
        {
            update(j,-1,0);
            ans[p[j].second]+=query(j,1);
        }
    }
    for(long long i=1;i<=n;i++)
    {
        printf("%lld ",ans[i]);
    }
    return 0;
}
